let CONTACT_API_BASE_URL=window.location.origin+"/api";function setContactFeedback(message,type="info"){var feedback=document.getElementById("contact-form-feedback");feedback&&(feedback.textContent=message,feedback.className="form-feedback "+type)}function initializeFaqAccordion(){document.querySelectorAll(".faq-question").forEach(button=>{button.setAttribute("aria-expanded","false"),button.addEventListener("click",function(){var faqItem=this.parentElement,isActive=faqItem.classList.contains("active");document.querySelectorAll(".faq-item").forEach(item=>{item.classList.remove("active"),item.querySelector(".faq-question")?.setAttribute("aria-expanded","false")}),isActive||(faqItem.classList.add("active"),this.setAttribute("aria-expanded","true"))})})}function initializeContactForm(){let contactForm=document.getElementById("contact-form");if(contactForm){let submitButton=contactForm.querySelector('button[type="submit"]');contactForm.addEventListener("submit",async event=>{event.preventDefault();event={name:document.getElementById("name").value.trim(),email:document.getElementById("email").value.trim(),message:document.getElementById("message").value.trim(),website:contactForm.querySelector('[name="website"]')?.value||""};submitButton.disabled=!0,submitButton.classList.add("is-loading"),submitButton.textContent="Skickar...",setContactFeedback("Skickar ditt meddelande...","info");try{var response=await fetch(CONTACT_API_BASE_URL+"/public/contact",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(event)}),data=await response.json();if(!response.ok)throw new Error(data.error||"Meddelandet kunde inte skickas");contactForm.reset(),setContactFeedback("Tack! Ditt meddelande har skickats och klubben återkommer så snart som möjligt.","success")}catch(error){console.error("Contact submission error:",error),setContactFeedback(error.message||"Ett fel uppstod. Försök igen senare.","error")}finally{submitButton.disabled=!1,submitButton.classList.remove("is-loading"),submitButton.textContent="Skicka meddelande"}})}}document.addEventListener("DOMContentLoaded",()=>{initializeFaqAccordion(),initializeContactForm()});